THOUGHT: I need to add code to eliminate bridge blocks. A bridge block is a block with exactly one predecessor and one successor, and it only contains PHI nodes and a terminator.

Let me add this logic right after the loop merging but before the LCSSA form maintenance.

```bash
# First, clean up my previous attempts
sed -i '1757,1765d' ./llvm/lib/Transforms/Scalar/LoopFuse.cpp
sed -i '2087s/true \/\* PreserveLCSSA \*\//false \/\* PreserveLCSSA \*\//g' ./llvm/lib/Transforms/Scalar/LoopFuse.cpp

# Now add the bridge block elimination logic
cat <<'EOF' >> ./llvm/lib/Transforms/Scalar/LoopFuse.cpp.tmp
    // Eliminate bridge blocks that may have been created during fusion.
    // A bridge block has exactly one predecessor and one successor, and
    // contains only PHI nodes and a terminator.
    SmallVector<BasicBlock *, 4> BlocksToErase;
    for (BasicBlock *BB : FC0.L->blocks()) {
      if (BB == FC0.Header || BB == FC1.Header)
        continue;

      // Check if this is a bridge block
      if (pred_size(BB) == 1 && succ_size(BB) == 1) {
        BasicBlock *Pred = *pred_begin(BB);
        BasicBlock *Succ = *succ_begin(BB);

        // Check if the block contains only PHI nodes and a terminator
        bool OnlyPHIAndTerm = true;
        for (Instruction &I : *BB) {
          if (&I == BB->getTerminator())
            break;
          if (!isa<PHINode>(&I)) {
            OnlyPHIAndTerm = false;
            break;
          }
        }

        if (OnlyPHIAndTerm) {
          // Redirect the predecessor to the successor
          Pred->getTerminator()->replaceUsesOfWith(BB, Succ);

          // Update PHI nodes in the successor
          Succ->replacePhiUsesWith(BB, Pred);

          BlocksToErase.push_back(BB);
        }
      }
    }

    // Erase the bridge blocks
    for (BasicBlock *BB : BlocksToErase) {
      LI.removeBlock(BB);
      DTU.deleteBB(BB);
    }
    DTU.flush();
EOF

